const systemPrompt = `Du bist ein freundlicher und professioneller Assessment Center Host und stellst immer exakt eine Folgefrage, bei der Firma "TechNova Solutions".
Du führst gerade das Erstgespräch für die Stelle als "Junior Java Developer".

DEINE ZIELE IM ERSTEN SCHRITT (SMALLTALK):
Lerne den Kandidaten kurz kennen, bevor das eigentliche Assessment beginnt. Führe ein flüssiges Gespräch.
Sorge dafür, dass du im Laufe des Gesprächs beiläufig folgende Infos erfährst, falls sie nicht schon genannt wurden:
1. Den Namen des Kandidaten.
2. Den aktuellen Wohnort (für uns wichtig wegen Remote/On-Site).
3. Grobe Vorerfahrung (Studium/Ausbildung/erste Jobs).

WICHTIGE VERHALTENSREGELN:
- Sprich wie ein Mensch, nicht wie ein Formular.
- VERBOTEN: Sag niemals Dinge wie "Ich habe den Namen notiert" oder "Fehlende Information: Wohnort".
- VERBOTEN: Sprich nicht über den Kandidaten in der dritten Person ("Der Kandidat hat gesagt..."), sondern sprich ihn direkt an ("Du hast gesagt...").
- Wenn der Kandidat etwas erzählt (z.B. Studium), geh kurz darauf ein ("Spannend, Softwaretechnik passt super zu uns"), bevor du die nächste Frage stellst.
- Stelle immer exakt EINE Folgefrage.

ABSCHLUSS DER PHASE:
Wenn du das Gefühl hast, du weißt grob, wer vor dir sitzt (Name, Ort, Background), dann leite charmant zum ersten Fach-Szenario über.`;

// Hole die strukturierten Messages aus dem Chat Memory Manager
const chatHistory = $('Chat Memory Manager').item.json.messages || [];

// Baue das Messages Array für Ollama
const messages = [
  {
    role: "system",
    content: systemPrompt
  }
];

// Füge alle History Messages hinzu 
for (const msg of chatHistory) {
  // Erst die User-Message
  if (msg.human) {
    messages.push({
      role: "user",
      content: msg.human
    });
  }

  if (msg.ai) {
    messages.push({
      role: "assistant",
      content: msg.ai
    });
  }
}

// Füge die aktuelle User-Message hinzu
messages.push({
  role: "user",
  content: $('When chat message received').first().json.chatInput
});

return {
  json: {
    model: "llama3.2:latest",
    stream: false,
    messages: messages
  }
};

// 1. Den gesamten Verlauf laden
const fullHistory = $('Chat Memory Manager').item.json.messages || [];

// 2. Definieren, wo der Schnitt war (z.B. nach 6 Nachrichten)
const cutOffPoint = 6; 

// 3. Slicing: Alles vor dem Cut-Point wird gelöscht (Host-Vergangenheit weg)
let customerOnlyHistory = fullHistory.slice(cutOffPoint);

// 4. Der System-Prompt für den Wütenden Kunden
const systemPrompt = `Du bist Michael Bauer, ein extrem verärgerter Kunde.
Dein Login funktioniert nicht. Du bist wütend und ungeduldig.
Reagiere auf das, was der Support (User) sagt.`;

// 5. Das neue Array initialisieren
const messages = [
  {
    role: "system",
    content: systemPrompt
  }
];

// Die bereinigte History anhängen
for (const msg of customerOnlyHistory) {
  if (msg.human) messages.push({ role: "user", content: msg.human });
  if (msg.ai) messages.push({ role: "assistant", content: msg.ai });
}

// Den aktuellen Input anhängen (Ohne Fallback, wenn leer, dann leer)
const currentUserInput = $('When chat message received').first().json.chatInput;
if (currentUserInput) {
    messages.push({ role: "user", content: currentUserInput });
}

return {
  json: {
    model: "llama3.2:latest", // Hier Modell wählen
    stream: false,
    messages: messages,
    options: {
        temperature: 0.9 // 0.9 macht ihn emotionaler/wütender als Standard
    }
  }
};

// 1. Input holen (Die einzelne Nachricht aus dem Loop)
const userText = $input.item.json.text;

// 2. System Prompt
const systemPrompt = `Du bist ein präziser HR-Assessment-Algorithmus.
Deine Aufgabe: Analysiere die folgende Aussage eines Kandidaten in einem Assessment Center.

BEWERTUNGSKRITERIEN (Skala 1.0 bis 5.0):
- kommunikation: Klarheit, Ausdrucksweise.
- empathie: Verständnis für die Gegenseite.
- problemloesung: Konstruktive Ansätze.
- professionalitaet: Sachlichkeit, Form.
- stressresistenz: Umgang mit Druck/Konflikten.

WICHTIG:
- Antworte AUSSCHLIESSLICH im JSON-Format.
- Kein Markdown (kein \`\`\`json).
- Wenn eine Kategorie aus dem kurzen Satz nicht ablesbar ist, gib den neutralen Wert 3.0.

Zwingendes Ausgabeformat:
{
  "kommunikation": 0.0,
  "empathie": 0.0,
  "problemloesung": 0.0,
  "professionalitaet": 0.0,
  "stressresistenz": 0.0,
  "kommentar": "Kurze Begründung"
}`;

// 3. Payload bauen
const payload = {
  model: "llama3.2:latest", // Passendes Modell auswählen
  stream: false,
  format: "json", // Zwinge Ollama zu validem Json
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user", content: userText }
  ]
};

return {
  json: payload
};

// Antwort bereinigen und in valides json wandeln
const ollamaResponse = $input.item.json.message.content;

try {
  const cleanData = JSON.parse(ollamaResponse);

  return {
    json: cleanData
  };
} catch (error) {
  return {
    json: {
      error: "Konnte JSON nicht parsen",
      raw_text: ollamaResponse
    }
  };
}

const history = $('Chat Memory Manager').item.json.messages || [];

// nur userinput rausfiltern
const userMessages = history.filter(msg => msg.human);

//umwandeln in n8n-Items, damit der Loop funktioniert
return userMessages.map((msg, index) => {
  return {
    json: {
      messageIndex: index + 1,
      text: msg.human
    }
  }
});

// 1. alle Ergebnisse aus dem Loop
const loopResults = $('Loop Over Items').all();
// 2. Speicher für die Summen der 5 Kategorien vorbereiten
let stats = {
    kommunikation: 0,
    empathie: 0,
    problemloesung: 0,
    professionalitaet: 0,
    stressresistenz: 0
};

let protocol = "";
let count = 0;

loopResults.forEach((item, index) => {
  // Das JSON aus dem Loop-Output holen (Parser Node)
  const data = item.json; 

  if (data && typeof data.kommunikation !== 'undefined') {

    // A) Protokoll-Text für diese einzelne Antwort bauen
    protocol += `### Antwort ${index + 1}\n`;
    protocol += `Analyse: "${data.kommentar}"\n`;
    protocol += `Werte: Komm: ${data.kommunikation}, Emp: ${data.empathie}, Prob: ${data.problemloesung}, Prof: ${data.professionalitaet}, Stress: ${data.stressresistenz}\n\n`;

    // B) Summen addieren für die Durchschnitte
    stats.kommunikation += parseFloat(data.kommunikation || 0);
    stats.empathie += parseFloat(data.empathie || 0);
    stats.problemloesung += parseFloat(data.problemloesung || 0);
    stats.professionalitaet += parseFloat(data.professionalitaet || 0);
    stats.stressresistenz += parseFloat(data.stressresistenz || 0);

    count++;
  }
});

// 3. Durchschnitte berechnen
let averages = {};
if (count > 0) {
    averages = {
        kommunikation: (stats.kommunikation / count).toFixed(1),
        empathie: (stats.empathie / count).toFixed(1),
        problemloesung: (stats.problemloesung / count).toFixed(1),
        professionalitaet: (stats.professionalitaet / count).toFixed(1),
        stressresistenz: (stats.stressresistenz / count).toFixed(1)
    };
} else {
    // Fallback falls keine Daten da sind
    averages = { kommunikation: 0, empathie: 0, problemloesung: 0, professionalitaet: 0, stressresistenz: 0 };
}

// 4. System-Prompt
const systemPrompt = `Du bist der Senior Recruiter "TechNova Solutions".
Das Assessment ist beendet. Hier ist die detaillierte Auswertung des Kandidaten basierend auf 5 Dimensionen.

--- DURCHSCHNITTSWERTE (Skala 1-5) ---
- Kommunikation: ${averages.kommunikation}
- Empathie: ${averages.empathie}
- Problemlösung: ${averages.problemloesung}
- Professionalität: ${averages.professionalitaet}
- Stressresistenz: ${averages.stressresistenz}

--- DETAILLIERTES PROTOKOLL DER ANTWORTEN ---
${protocol}
--- PROTOKOLL ENDE ---

DEINE AUFGABE:
Schreibe ein abschließendes, professionelles Gutachten an den Kandidaten.
1. Fasse die Leistung zusammen. Gehe dabei KONKRET auf die 5 Kategorien ein (z.B. "Deine Empathie war stark, aber...").
2. Nutze das Protokoll, um Beispiele für gutes oder schlechtes Verhalten zu nennen.
3. Gib am Ende eine klare Empfehlung (Einstellen oder Ablehnen) basierend auf dem Gesamtbild.
4. Sprich den Kandidaten direkt mit "Du" an.`;

// 5. Das Paket für den HTTP Request
return {
  json: {
    model: "llama3.2:latest", 
    stream: false,
    messages: [
      {
        role: "system",
        content: systemPrompt
      },
      {
        role: "user",
        content: "Bitte erstelle jetzt das finale Gutachten."
      }
    ]
  }
};
